import kotlinx.coroutines.*
import java.io.IOException

fun main() = runBlocking {
    // 使用 supervisorScope：子协程异常不会取消同级
    supervisorScope {
        val job1 = launch {
            delay(100)
            println("Job1 completed")
        }
        val job2 = launch {
            delay(50)
            throw IOException("Job2 failed")
        }
        // 等待所有子协程（包括失败的）
        joinAll(job1, job2)
    }
    println("SupervisorScope finished. Job1 still ran.")

    println("---")

    // 使用 coroutineScope：子协程异常会取消整个作用域
    try {
        coroutineScope {
            val job3 = launch {
                delay(100)
                println("Job3 completed")
            }
            val job4 = launch {
                delay(50)
                throw IOException("Job4 failed")
            }
            // job3 会被自动取消
        }
    } catch (e: IOException) {
        println("Caught exception: ${e.message}")
    }
    println("CoroutineScope finished.")
}

// 辅助函数：等待多个 Job
private suspend fun joinAll(vararg jobs: Job) {
    jobs.forEach { it.join() }
}

